query:
UPDATE leads l
SET ultimaInteracao = (
  SELECT MAX(lh.createdAt)
  FROM lead_history lh
  WHERE lh.leadId = l.id
)
WHERE EXISTS (
  SELECT 1 FROM lead_history lh WHERE lh.leadId = l.id
);

